// Capture draft responses and prepare WF9 call
const aiResponse = $input.first().json;
const draftText = aiResponse.message?.content || aiResponse.text || JSON.stringify(aiResponse);
const context = $('Step 5: Combine Content1').first().json;

return [{
  json: {
    draftResponses: draftText,
    funderName: context.funderName,
    funderFocus: context.funderFocus,
    rfpText: context.rfpText,
    planeIssueId: context.planeIssueId
  }
}];

// Enhanced Compliance Review (includes budget)
  const context = $('Step 5: Combine Content1').first().json;
  const alignmentResponse = $input.first().json;

  let alignment = {};
  try {
    const text = alignmentResponse.message?.content || alignmentResponse.text || '';
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) alignment = JSON.parse(jsonMatch[0]);
  } catch (e) {
    alignment = { alignedResponses: [], overall_alignment_score: 0 };
  }

  const alignedResponses = alignment.alignedResponses || [];

  // Initialize warnings and sections as explicit string/object arrays
  const warnings = [];
  const sections = [];

  let totalChecks = 0;
  let passedChecks = 0;

  for (const q of context.questions) {
    const aligned = alignedResponses.find(a => a.question_id === q.question_id);
    const response = aligned ? aligned.aligned_response : '';
    const wordCount = aligned ? aligned.word_count : (response ? response.split(/\s+/).length : 0);
    const alignmentNotes = aligned ? aligned.alignment_notes : '';
    const missionOverlap = aligned ? aligned.mission_overlap : '';

    // Initialize issues as explicit array
    const issues = [];

    // Check response exists
    totalChecks++;
    if (response && response.length > 50) {
      passedChecks++;
    } else {
      issues.push('Response missing or too short');
      warnings.push('Section ' + q.question_id + ': Response missing or too short');
    }

    // Check word limit
    if (q.word_limit) {
      totalChecks++;
      if (wordCount <= q.word_limit) {
        passedChecks++;
      } else {
        issues.push('Over word limit: ' + wordCount + '/' + q.word_limit);
        warnings.push('Section ' + q.question_id + ': ' + wordCount + ' words exceeds limit of ' + q.word_limit);
      }
    }

    // Check required docs available
    if (q.required_docs) {
      for (const doc of q.required_docs) {
        if (doc === 'none') continue;
        totalChecks++;
        const found = (q.documentLinks && q.documentLinks.some(d => d.type === doc));
        if (found) {
          passedChecks++;
        } else {
          issues.push('Missing attachment: ' + doc);
        }
      }
    }

    // Check for weak language
    totalChecks++;
    const weakPhrases = ['we hope to', 'we might', 'possibly', 'we think', 'maybe'];
    const hasWeak = weakPhrases.some(p => (response || '').toLowerCase().includes(p));
    if (!hasWeak) {
      passedChecks++;
    } else {
      issues.push('Contains weak/uncertain language');
      warnings.push('Section ' + q.question_id + ': Contains weak language - strengthen assertions');
    }

    sections.push({
      questionId: q.question_id,
      question: q.question_text,
      response: response,
      wordCount: wordCount,
      wordLimit: q.word_limit || null,
      sectionType: q.section_type,
      attachments: q.required_docs || [],
      alignmentNotes: alignmentNotes,
      missionOverlap: missionOverlap,
      issues: issues
    });
  }

  if (context.missingNarratives && context.missingNarratives.length > 0) {
    warnings.push('Missing narratives: ' + context.missingNarratives.join(', '));
  }
  if (context.missingDocs && context.missingDocs.length > 0) {
    warnings.push('Missing documents: ' + context.missingDocs.join(', '));
  }

  // Check budget
  if (context.budget && context.budget.generated) {
    totalChecks++;
    passedChecks++; // Budget was generated

    if (context.budget.warnings && context.budget.warnings.length > 0) {
      for (const warning of context.budget.warnings) {
        warnings.push('Budget: ' + warning);
      }
    }
  } else {
    totalChecks++;
    warnings.push('Budget not generated - run budget generator first');
  }

  totalChecks++;
  const answeredCount = sections.filter(s => s.response && s.response.length > 50).length;
  if (answeredCount === context.questions.length) {
    passedChecks++;
  } else {
    warnings.push('Only ' + answeredCount + '/' + context.questions.length + ' questions fully answered');
  }

  const complianceScore = totalChecks > 0 ? Math.round((passedChecks / totalChecks) * 100) : 0;

  const proposal = {
    title: 'Grant Proposal - ' + context.funderName,
    deadline: context.deadline,
    funder: context.funderName,
    focus: context.funderFocus,
    planeIssueId: context.planeIssueId,
    alignmentScore: alignment.overall_alignment_score || 0,
    funderLanguageAdopted: alignment.funder_language_adopted || [],
    missionOverlap: alignment.mission_overlap_summary || '',
    sections: sections,
    warnings: warnings,
    complianceScore: complianceScore,
    budget: context.budget || {}
  };

  return [{ json: proposal }];

let grantItems = [];

// Try the first node
try {
  const fetchEligible = $('Fetch Eligible Grants1').all();
  if (fetchEligible.length > 0) {
    grantItems = fetchEligible;
  } else {
    // fallback to second node
